<?php
namespace App\Models;use Illuminate\Database\Eloquent\Factories\HasFactory;use Illuminate\Database\Eloquent\Model;
class ParticipantDataRequest extends Model{use HasFactory;protected $fillable=['person_id','project_person_id','requested_by_user_id','type','status','request_details','resolution_note','identity_verification_method','resolved_by_user_id','identity_verified_at','resolved_at','completed_at','last_downloaded_at'];protected $casts=['identity_verified_at'=>'datetime','resolved_at'=>'datetime','completed_at'=>'datetime','last_downloaded_at'=>'datetime'];public function person(){return $this->belongsTo(Personen::class,'person_id');}public function participation(){return $this->belongsTo(ProjektHasPersonen::class,'project_person_id');}public function requester(){return $this->belongsTo(User::class,'requested_by_user_id');}public function resolver(){return $this->belongsTo(User::class,'resolved_by_user_id');}}
